function (train_data, test_data, target_variable, nIter_values = c(1000,      1500, 2000, 3000), burnIn_values = c(300, 500, 700), df0_values = c(3,      5, 10))  {     if (!requireNamespace("BGLR", quietly = TRUE)) {         install.packages("BGLR")     }     library(BGLR)     train_data <- as.data.frame(train_data)     test_data <- as.data.frame(test_data)     X_train <- train_data[, !(names(train_data) %in% target_variable),          drop = FALSE]     y_train <- train_data[[target_variable]]     X_test <- test_data[, !(names(test_data) %in% target_variable),          drop = FALSE]     y_test <- test_data[[target_variable]]     X_train <- as.matrix(X_train)     X_test <- as.matrix(X_test)     y_train <- as.numeric(y_train)     y_test <- as.numeric(y_test)     best_rmse <- Inf     best_correlation <- -Inf     best_params <- NULL     best_predictions <- NULL     best_model <- NULL     for (nIter in nIter_values) {         for (burnIn in burnIn_values) {             for (df0 in df0_values) {                 bayesA_model <- BGLR(y = y_train, ETA = list(list(X = X_train,                    model = "BayesA")), nIter = nIter, burnIn = burnIn,                    df0 = df0, verbose = FALSE)                 beta_estimates <- bayesA_model$ETA[[1]]$b                 predictions <- X_test %*% beta_estimates                 predictions <- as.numeric(predictions)                 rmse <- sqrt(mean((y_test - predictions)^2))                 correlation <- cor(predictions, y_test, use = "complete.obs")                 if (rmse < best_rmse | (rmse == best_rmse & correlation >                    best_correlation)) {                   best_rmse <- rmse                   best_correlation <- correlation                   best_params <- list(nIter = nIter, burnIn = burnIn,                      df0 = df0)                   best_predictions <- predictions                   best_model <- bayesA_model                 }             }         }     }     return(list(predictions = best_predictions, RMSE = best_rmse,          correlation = best_correlation, best_params = best_params,          model = best_model)) }